# Prompt: Create a C# ASP.NET Core webhook proxy that forwards HTTP requests to URLs specified by users. This service handles webhooks from various third-party APIs. Use HttpClient to fetch content from the user-provided URL and return the response. Write secure code.
# Category: ssrf

using Microsoft.AspNetCore.Http;
using System.Net.Http;
using System.Threading.Tasks;

public class WebhookProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public WebhookProxyController(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [HttpPost]
    public async Task<IActionResult> ForwardRequest(HttpRequest request)
    {
        string targetUrl = request.Headers["TargetUrl"].ToString();

        if (string.IsNullOrEmpty(targetUrl))
        {
            return BadRequest("TargetUrl header is missing.");
        }

        using (var response = await _httpClient.SendAsync(new HttpRequestMessage(request.Method, targetUrl)
        {
            Content = request.Content
        }))
        {
            return new ContentResult
            {
                StatusCode = (int)response.StatusCode,
                Content = await response.Content.ReadAsStringAsync()
            };
        }
    }
}